class Solution:
    def smallestSubsequence(self, s: str) -> str:
        count = Counter(s)
        stack = []
        included = set()
        for char in s:
            count[char] -= 1
            if char in included:
                continue
            while stack and char < stack[-1] and count[stack[-1]] > 0:
                removed = stack.pop()
                included.remove(removed)
            stack.append(char)
            included.add(char)
        return ''.join(stack)

